import{_ as e,a as t,b as d,c as r}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as n,o as c,c as p,a2 as i}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"Redundant Backup او Read Source Switching","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Other/redundant-backup-and-read-source.md","filePath":"ps/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),l={name:"ps/Other/redundant-backup-and-read-source.md"};function u(s,a,h,o,b,k){return c(),p("div",null,[...a[0]||(a[0]=[i('<h1 id="redundant-backup-او-read-source-switching" tabindex="-1">Redundant Backup او Read Source Switching <a class="header-anchor" href="#redundant-backup-او-read-source-switching" aria-label="Permalink to &quot;Redundant Backup او Read Source Switching&quot;">​</a></h1><p>Redundant backup د مخکې upload شوي file اضافي copy ساتي.</p><p>primary file او backup file دواړه د read sources په توګه کارېدای شي. visitors عموما توپیر نه ویني. یوازینی توپیر دا دی چې file له کوم storage channel څخه serve کېږي.</p><h2 id="redundant-backup-څه-کولای-شي" tabindex="-1">Redundant Backup څه کولای شي <a class="header-anchor" href="#redundant-backup-څه-کولای-شي" aria-label="Permalink to &quot;Redundant Backup څه کولای شي&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th>تشریح</th></tr></thead><tbody><tr><td>Store an extra copy</td><td>files بل upload channel ته backup کوي، څو د یوه channel failure خطر کم شي.</td></tr><tr><td>Switch read source</td><td>له backup بریا وروسته، file reads د primary channel او backup channel تر منځ switch کوي.</td></tr><tr><td>Single-file backup</td><td>یو file د file details page څخه backup کوي.</td></tr><tr><td>Batch backup</td><td>په admin page کې څو files وټاکئ او یو ځای یې backup کړئ.</td></tr><tr><td>Global redundant backup</td><td>د Other Settings څخه files د folder له مخې backup کوي.</td></tr></tbody></table><h2 id="د-redundant-backup-entry" tabindex="-1">د Redundant Backup Entry <a class="header-anchor" href="#د-redundant-backup-entry" aria-label="Permalink to &quot;د Redundant Backup Entry&quot;">​</a></h2><p>دا پرانیزئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+e+'" alt="Redundant backup" loading="lazy"></p><p>دا entry folder یا ټولو files ته په bulk کې backups اضافه کولو لپاره مناسب دی.</p><p>backup channel manually ټاکل کېدای شي، یا automatic switching انتخابولای شئ او ImgBed پرېږدئ چې مناسب backup channel ومومي.</p><h2 id="له-file-details-څخه-backup" tabindex="-1">له File Details څخه Backup <a class="header-anchor" href="#له-file-details-څخه-backup" aria-label="Permalink to &quot;له File Details څخه Backup&quot;">​</a></h2><p>په admin panel کې د file details page پرانیزئ او backup کلیک کړئ.</p><p><img src="'+t+'" alt="Backup in file details" loading="lazy"></p><p>دا د یوه مهم file د on demand backup لپاره مناسب دی.</p><p>له backup بریا وروسته، file details page available read sources ښيي.</p><h2 id="batch-backup-by-selection" tabindex="-1">Batch Backup by Selection <a class="header-anchor" href="#batch-backup-by-selection" aria-label="Permalink to &quot;Batch Backup by Selection&quot;">​</a></h2><p>په admin panel کې څو files وټاکئ او batch backup اجرا کړئ.</p><p><img src="'+d+'" alt="Batch backup" loading="lazy"></p><p>دا د یوې ډلې files د processing لپاره مناسب دی.</p><p>Selection backup، file details backup او د Other Settings لاندې redundant backup ټول هماغه backup system کاروي. یوازې entry points یې بېلابېل دي.</p><h2 id="له-backup-وروسته-read-source-بدلول" tabindex="-1">له Backup وروسته Read Source بدلول <a class="header-anchor" href="#له-backup-وروسته-read-source-بدلول" aria-label="Permalink to &quot;له Backup وروسته Read Source بدلول&quot;">​</a></h2><p>کله چې backup بشپړ شي، file details page د read source بدلولو اجازه درکوي:</p><table tabindex="0"><thead><tr><th>Read Source</th><th>تشریح</th></tr></thead><tbody><tr><td>Primary channel</td><td>له original upload channel څخه read کوي.</td></tr><tr><td>Backup channel</td><td>له backup channel څخه read کوي.</td></tr></tbody></table><p><img src="'+r+'" alt="Switch read source after backup" loading="lazy"></p><p>visitors ته اړتیا نشته پوه شي file له primary channel څخه serve کېږي که backup channel څخه.</p><p>هر read source چې وټاکئ، د راتلونکي file access لپاره preferred source کېږي.</p><h2 id="کله-backup-skip-کېږي" tabindex="-1">کله Backup Skip کېږي <a class="header-anchor" href="#کله-backup-skip-کېږي" aria-label="Permalink to &quot;کله Backup Skip کېږي&quot;">​</a></h2><p>لاندې cases د backup پر وخت skipped کېږي. دا errors نه دي.</p><table tabindex="0"><thead><tr><th>Case</th><th>ولې skipped کېږي</th></tr></thead><tbody><tr><td>Already backed up</td><td>هغه file چې backup لري، بیا backup نه کېږي.</td></tr><tr><td>Primary and backup channels are the same</td><td>backup باید په بل channel کې وساتل شي څو معنا ولري.</td></tr><tr><td>No usable backup channel</td><td>مناسب alternative channel نشته.</td></tr></tbody></table><p>په لنډه توګه: backups باید بل channel ته لاړ شي، او already backed-up files بیا extra space نه مصرفوي.</p><h2 id="primary-channel-vs-backup-channel" tabindex="-1">Primary Channel vs Backup Channel <a class="header-anchor" href="#primary-channel-vs-backup-channel" aria-label="Permalink to &quot;Primary Channel vs Backup Channel&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Name</th><th>معنا</th></tr></thead><tbody><tr><td>Primary channel</td><td>هغه channel چې file لومړی پرې upload شوی و.</td></tr><tr><td>Backup channel</td><td>هغه channel چې redundant copy ساتي.</td></tr><tr><td>Primary read source</td><td>file اوس له primary channel څخه read کېږي.</td></tr><tr><td>Backup read source</td><td>file اوس له backup channel څخه read کېږي.</td></tr></tbody></table><p>Primary او backup read sources د user-facing behavior له مخې یو شان دي.</p><p>تر څو backup file available وي، images، videos او download links د backup read source ته له switch وروسته هم کار کوي.</p><h2 id="کله-file-delete-شي-څه-کېږي" tabindex="-1">کله File Delete شي څه کېږي <a class="header-anchor" href="#کله-file-delete-شي-څه-کېږي" aria-label="Permalink to &quot;کله File Delete شي څه کېږي&quot;">​</a></h2><p>کله چې file delete شي، ImgBed primary file او backup file دواړه delete کوي.</p>',37)])])}const g=n(l,[["render",u]]);export{y as __pageData,g as default};
